#' Evaluate log p(obs, z | theta) and log q(z | obs, theta) for augmented trees
#'
#' Given a list of augmented trees (produced by \code{\link{augment_trees}})
#' and a parameter vector, computes for each tree:
#' \itemize{
#'   \item \code{logf[i] = log p(obs, z_i | theta)} (model log-likelihood)
#'   \item \code{logg[i] = log q(z_i | obs, theta)} (proposal log-probability)
#' }
#' Both are evaluated at the supplied \code{pars}, regardless of which
#' parameters were used to simulate the trees.  This is essential for
#' shared-tree (Mode 2) evaluation where trees simulated at one particle
#' are scored at another.
#'
#' @param pars Numeric vector of 8 model parameters.
#' @param trees List of augmented-tree data frames (output of
#'   \code{\link{augment_trees}}).
#' @param model Integer vector \code{c(use_N, use_P, use_E)}.
#' @param link Link function: \code{0} = linear, \code{1} = exponential.
#' @return A named list:
#' \describe{
#'   \item{logf}{Numeric vector of \code{log p(obs, z_i | theta)}.}
#'   \item{logg}{Numeric vector of \code{log q(z_i | obs, theta)}.}
#' }
#' @export
eval_logf <- function(pars, trees, model = as.integer( c(0, 0, 0)), link = 0L) {
    .Call('_emphasis_eval_logf_cpp', PACKAGE = 'emphasis', pars, trees, model, link)
}

#' Draw augmented trees via importance sampling
#'
#' Augments an observed extant tree (given by its branching times) with
#' stochastically drawn extinct lineages, and returns the simulated trees
#' together with their log proposal probabilities.  Scoring (\code{logf})
#' and IS aggregation (\code{fhat}) are intentionally left to the R layer
#' via \code{\link{eval_logf}} and \code{.is_fhat}.
#'
#' @param brts Numeric vector of branching times (crown age first,
#'   sorted decreasing).
#' @param pars Numeric vector of 8 model parameters
#'   \code{c(beta_0, beta_N, beta_P, beta_E, gamma_0, gamma_N, gamma_P, gamma_E)}.
#' @param sample_size Number of valid augmented trees to collect.
#' @param maxN Maximum total augmentation attempts (including failures).
#' @param max_missing Maximum extinct lineages per augmented tree.
#' @param max_lambda Upper bound on the speciation rate (thinning bound).
#' @param num_threads Threads for parallel augmentation.
#' @param model Integer vector \code{c(use_N, use_P, use_E)}.
#' @param link Link function: \code{0} = linear, \code{1} = exponential.
#' @return A named list:
#' \describe{
#'   \item{trees}{List of augmented-tree data frames.}
#'   \item{logf}{Per-tree log p(obs, z | theta).}
#'   \item{logg}{Per-tree log q(z | obs, theta).}
#'   \item{rejected}{Unhandled rejections.}
#'   \item{rejected_overruns}{Rejected: too many extinct lineages.}
#'   \item{rejected_lambda}{Rejected: lambda bound exceeded.}
#'   \item{rejected_zero_weights}{Rejected: zero IS weight.}
#'   \item{time}{Elapsed time (ms).}
#' }
#' @export
augment_trees <- function(brts, pars, sample_size, maxN, max_missing, max_lambda, num_threads, model = as.integer( c(0, 0, 0)), link = 0L) {
    .Call('_emphasis_rcpp_mce', PACKAGE = 'emphasis', brts, pars, sample_size, maxN, max_missing, max_lambda, num_threads, model, link)
}

#' function to perform one step of the E-M algorithm
#' @param brts vector of branching times
#' @param init_pars vector of initial parameter files
#' @param sample_size number of samples
#' @param maxN maximum number of failed trees
#' @param max_missing maximum number of species missing
#' @param max_lambda maximum speciation rate
#' @param lower_bound vector of lower bound values for optimization, should
#' be equal in length to the vector of init_pars
#' @param upper_bound vector of upper bound values for optimization, should
#' be equal in length to the vector of init_pars
#' @param xtol_rel relative tolerance for optimization
#' @param num_threads number of threads used.
#' @param copy_trees if set to true, the trees generated are returned as well
#' @param model integer vector of length 3: c(use_N, use_P, use_E)
#' @param link link function: 0 = linear (max(0,...)), 1 = exponential
#' @param rconditional R function that evaluates the GAM function.
#' @return a list with the following components:
#' \itemize{
#'  \item{trees}{list of trees}
#'  \item{rejected}{number of rejected trees}
#'  \item{rejected_overruns}{number of trees rejected due to too large size}
#'  \item{rejected_lambda}{number of trees rejected due to lambda errors}
#'  \item{rejected_zero_weights}{number of trees rejected to zero weight}
#'  \item{estimates}{vector of estimates}
#'  \item{nlopt}{nlopt status}
#'  \item{fhat}{vector of fhat values}
#'  \item{time}{time elapsed}
#'  \item{weights}{vector of weights}
#'  \item{logf}{vector of log p(obs, z_i | theta) for each valid tree}
#'  \item{logg}{vector of log q(z_i | obs, theta) for each valid tree}
#' }
#' @export
em_cpp <- function(brts, init_pars, sample_size, maxN, max_missing, max_lambda, lower_bound, upper_bound, xtol_rel, num_threads, copy_trees, model = as.integer( c(0, 0, 0)), link = 0L, rconditional = NULL) {
    .Call('_emphasis_rcpp_mcem', PACKAGE = 'emphasis', brts, init_pars, sample_size, maxN, max_missing, max_lambda, lower_bound, upper_bound, xtol_rel, num_threads, copy_trees, model, link, rconditional)
}

